class a{static baseUrl(){return window.localStorage.getItem("base_url")||window.location.origin}static getAppUrl(t){return`${this.baseUrl()}/${t}`}static getQueryStringValue(t){return new URLSearchParams(window.location.search).get(t)}static isFunction(t){return typeof t=="function"}static isUndefined(t){return typeof t>"u"}static splitNameBySlas(t){if(t.includes("/")){let r=t.split("/");return r[r.length-1]}return t}}export{a};
